COMMENT "app版本信息视图" AS (SELECT `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`product_id`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`date`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`old_value`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`Id`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`new_value`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`event_type`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`release_note`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`release_date`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`updatetime`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`inittime`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`sr_createtime`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`sr_updatetime`, `dwd`.`dwd_competitor_data_ai_app_timeline_view`.`etl_time`
FROM `dwd`.`dwd_competitor_data_ai_app_timeline_view`);